#graphql
  query LocalizationTranslationsMarketScopedRead(
    $resourceId: ID!
    $marketId: ID!
    $resourceIds: [ID!]!
    $marketsFirst: Int!
  ) {
    translatableResource(resourceId: $resourceId) {
      resourceId
      translatableContent {
        key
        value
        digest
        locale
        type
      }
      translations(locale: "es", marketId: $marketId) {
        key
        value
        locale
        outdated
        updatedAt
        market {
          id
        }
      }
    }
    byIds: translatableResourcesByIds(first: 10, resourceIds: $resourceIds) {
      nodes {
        resourceId
        translatableContent {
          key
          value
          digest
          locale
          type
        }
      }
    }
    markets(first: $marketsFirst) {
      nodes {
        id
        name
        handle
        status
        type
      }
    }
    allShopLocales: shopLocales {
      locale
      name
      primary
      published
      marketWebPresences {
        id
        subfolderSuffix
      }
    }
  }

query LocalizationMutationTargetsHydrate($ids: [ID!]!) {
  nodes(ids: $ids) {
    __typename
    ... on Market {
      id
      name
      handle
      status
      type
    }
    ... on MarketWebPresence {
      id
      subfolderSuffix
      domain {
        id
        host
        url
        sslEnabled
      }
      rootUrls {
        locale
        url
      }
      defaultLocale {
        locale
        name
        primary
        published
      }
      alternateLocales {
        locale
        name
        primary
        published
      }
      markets(first: 250) {
        nodes {
          id
          name
          handle
          status
          type
        }
      }
    }
  }
}

